export type { Locale }

const I18nContext = createContext<{
  locale: Locale
  setLocale: (l: Locale) => void
  dir: 'ltr' | 'rtl'
  t: (key: string) => string
}>({
  locale: 'en',
  setLocale: () => {},
  dir: 'ltr',
  t: (key: string) => key,
})

function getInitialLocale(): Locale {
  if (typeof window === 'undefined') return 'en'
  const saved = localStorage.getItem('oneway-locale') as Locale | null
  if (saved && translations[saved]) return saved
  return 'en'
}

export function I18nProvider({ children }: { children: React.ReactNode }) {
  const [locale, setLocaleState] = useState<Locale>(getInitialLocale)

  useEffect(() => {
    document.documentElement.lang = locale
    document.documentElement.dir = locale === 'ar' ? 'rtl' : 'ltr'
  }, [locale])

  const setLocale = useCallback((l: Locale) => {
    setLocaleState(l)
    localStorage.setItem('oneway-locale', l)
  }, [])

  const t = useCallback((key: string): string => {
    return translations[locale]?.[key] ?? translations.en?.[key] ?? key
  }, [locale])

  const dir = locale === 'ar' ? 'rtl' : 'ltr'

  return (
    <I18nContext.Provider value={{ locale, setLocale, dir, t }}>
      {children}
    </I18nContext.Provider>
  )
}

export function useTranslation() {
  return useContext(I18nContext)
}

export const localeNames: Locale[] = ['en', 'ar', 'fr', 'es', 'de', 'zh', 'ja', 'ru']
